import {
  Box,
  Button,
  Drawer,
  DrawerBody,
  DrawerContent,
  DrawerHeader,
  DrawerOverlay,
  Flex,
  Heading,
  Text,
  useToast,
} from "@chakra-ui/react";
import { Link, useNavigate } from "react-router-dom";
import { RxCross2 } from "react-icons/rx";
import { useDispatch, useSelector } from "react-redux";
import { BiUserCircle } from "react-icons/bi";
import { capitalizeFirstLetter } from "../Redux/UserReducer/action";
import { FaUserShield } from "react-icons/fa";
import { IoIosArrowForward } from "react-icons/io";
import axios from "axios";
import { actionUserLogout } from "../Redux/UserReducer/actionType";
import { showToast } from "./SignUp";

export function NavBarDrawer({ isOpen, onClose }) {
  const userStore = useSelector((store) => store.UserReducer);
  const navigate = useNavigate();
  const toast = useToast();
  const dispatch = useDispatch();

  const drawerItems = {
    Explore: ["Development", "Business", "IT & Software", "Design"],
    Goals: ["Take a free course", "Earn a Degree", "Earn a Certificate"],
  };

  const handleLogoutClick = () => {
    const token = userStore?.token;

    axios
      .post(
        "https://elearning-platform-using-mern-j5py.vercel.app/users/logout",
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      )
      .then(() => {
        localStorage.setItem(
          "user",
          JSON.stringify({
            email: "",
            name: "",
            role: "",
            token: "",
            isAuth: false,
          })
        );
        dispatch(actionUserLogout());
        showToast({
          toast,
          message: "Logged out successfully",
          color: "green",
        });
        navigate("/");
      })
      .catch((err) => console.log(err));
  };

  return (
    <Drawer placement="left" onClose={onClose} isOpen={isOpen}>
      <DrawerOverlay />
      <DrawerContent maxW="280px">
        {/* HEADER */}
        <DrawerHeader
          display="flex"
          justifyContent="space-between"
          alignItems="center"
          borderBottom="1px solid #eee"
        >
          <Text
            fontSize="xl"
            fontWeight="bold"
            color="#A435F0"
            cursor="pointer"
            onClick={() => navigate("/")}
          >
            SRM
          </Text>

          <RxCross2 cursor="pointer" onClick={onClose} />
        </DrawerHeader>

        {/* BODY */}
        <DrawerBody p={4}>
          {/* AUTH */}
          {!userStore?.isAuth ? (
            <Flex direction="column" gap={3} mb={5}>
              <Button
                variant="outline"
                onClick={() => navigate("/login")}
              >
                Log in
              </Button>

              <Button
                bg="#A435F0"
                color="white"
                _hover={{ bg: "#8710d8" }}
                onClick={() => navigate("/signup")}
              >
                Sign up
              </Button>
            </Flex>
          ) : (
            <Box mb={5}>
              <Flex align="center" gap={3}>
                {userStore?.role === "admin" ||
                userStore?.role === "teacher" ? (
                  <FaUserShield size="1.8rem" color="#A435F0" />
                ) : (
                  <BiUserCircle size="1.8rem" color="#A435F0" />
                )}

                <Box>
                  <Text fontWeight="bold">
                    {capitalizeFirstLetter(userStore?.name)}
                  </Text>
                  <Text fontSize="xs" color="gray.500">
                    {capitalizeFirstLetter(userStore?.role)}
                  </Text>
                </Box>
              </Flex>

              <Button
                size="sm"
                mt={3}
                w="100%"
                onClick={handleLogoutClick}
              >
                Logout
              </Button>
            </Box>
          )}

          {/* USER MENU */}
          {userStore?.isAuth && (
            <Box mb={5}>
              <Link to="/profile">
                <Flex justify="space-between" py={2}>
                  <Text>Your Account</Text>
                  <IoIosArrowForward />
                </Flex>
              </Link>

              <Link to="/home">
                <Flex justify="space-between" py={2}>
                  <Text>Dashboard</Text>
                  <IoIosArrowForward />
                </Flex>
              </Link>
            </Box>
          )}

          {/* CATEGORIES */}
          {Object.entries(drawerItems).map(([category, items]) => (
            <Box key={category} mb={5}>
              <Heading size="xs" mb={2} color="gray.500">
                {category}
              </Heading>

              {items.map((item) => (
                <Text
                  key={item}
                  py={2}
                  cursor="pointer"
                  _hover={{ color: "#A435F0" }}
                >
                  {item}
                </Text>
              ))}
            </Box>
          ))}
        </DrawerBody>
      </DrawerContent>
    </Drawer>
  );
}
